#include <stdio.h>

int main() {
    int numbers[5] = {10, 20, 30, 40, 50};

    printf("প্রথম উপাদান: %d\n", numbers[0]);
    numbers[2] = 99; // পরিবর্তন করা

    for (int i = 0; i < 5; i++) {
        printf("%d ", numbers[i]);
    }
    return 0;
}

#include <stdio.h>
#include <string.h>

int main() {
    char name[20] = "Bangladesh";

    printf("নাম: %s\n", name);
    printf("লম্বা: %lu\n", strlen(name));

    char greeting[50];
    strcpy(greeting, "Hello, ");
    strcat(greeting, name);
    printf("%s\n", greeting); // Hello, Bangladesh

    return 0;
}
